-- Reestructura pasos de árbol/cartas/mascotas al formato __SKILLS__ (icono + explicación).
-- UPDATE dirigido: no borra ni despublica las guías, no reinicia el progreso de los usuarios.

update public.guide_steps
set content = $IMPERIUM$El árbol de Swordsman es la base de todo el build: aquí sientas los cimientos de ataque físico antes de pasar a Crusader y, después, a Paladin. Cada ficha lleva el icono de la habilidad tal y como la verás en el juego, la prioridad que le damos y para qué sirve.

__SKILLS__[{"name":"Sword Mastery","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_JianXiShuLianDu.webp","tag":"Al máximo","desc":"+30 de PATK permanente. PATK es tu ataque físico: cuanto más alto, más daño hacen tus golpes normales y tus habilidades físicas. Es pasiva (funciona sola, no hay que activarla) y no cuesta nada mantenerla al día, así que no hay motivo para retrasarla."},{"name":"Bash","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_kuangJi.webp","tag":"Al máximo","desc":"Tu primer golpe fuerte de verdad: inflige 350% + 200 de daño físico (PDMG) a un único objetivo y suma +15 de HIT. HIT es tu puntería: cuanto más tengas, menos fallas contra rivales escurridizos."},{"name":"Fatal Blow","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_GongJiRuoDian.webp","tag":"Al máximo","desc":"Añade un 25% de probabilidad de aturdir cada vez que conectas ese mismo Bash. Un rival aturdido se queda unos instantes sin poder moverse ni atacar."},{"name":"Increase Recuperative Power","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_KuaiSuHuiFu.webp","tag":"Recomendada","desc":"Mejora tu regeneración de HP pasiva, es decir, la vida que recuperas tú solo con el paso del tiempo. Es algo que necesitas antes de acumular el HP masivo de las siguientes fases del build."},{"name":"Magnum Break","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_NuBao.webp","tag":"Unos pocos puntos","desc":"Inflige 250% + 100 de daño físico de elemento Fuego a hasta 10 objetivos a tu alrededor: es un golpe en área, no contra un solo enemigo. No es prioridad, pero unos pocos puntos aquí rinden mucho en peleas de gremio donde el rival se amontona."},{"name":"Berserk","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_KuangBaoZhuangTai.webp","tag":"Barato","desc":"Solo +10 de PATK, pero cuesta tan poco que no tiene sentido dejarlo fuera."},{"name":"Provoke","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_TiaoXing.webp","tag":"Si sobran puntos","desc":"Déjala para el final: rinde casi solo contra monstruos y en combate contra jugadores apenas se nota."},{"name":"Endure","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_BaTi.webp","tag":"Si sobran puntos","desc":"Mismo caso que Provoke: rinde casi solo contra monstruos y en combate contra jugadores apenas se nota."}]

Con este tramo cubierto ya puedes dar el salto a Crusader, que es donde el build empieza a tomar forma.$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'paladin-build-pvp-gvg')
  and order_index = 2;

update public.guide_steps
set content = $IMPERIUM$Crusader es tu segundo trabajo, y aquí el build empieza a definirse de verdad. Sigue este orden.

__SKILLS__[{"name":"Faith","img":"https://www.roochub.com/icons/UI_Icon_Skill_Crusader_XinRen.webp","tag":"Obligatorio · al máximo","desc":"+3,000 de Max HP permanentes y reduce un 30% el daño de elemento Holy que recibes. Max HP es tu vida total, y Holy (Sagrado) es uno de los elementos del juego: hay clases y monstruos que hacen daño de ese tipo. Es la base de toda tu supervivencia a partir de aquí."},{"name":"Demon Bane","img":"https://www.roochub.com/icons/UI_Icon_Skill_Acolyte_TianShiZhiQu.webp","tag":"Al máximo","desc":"+20 de PATK y +20 de PDEF permanentes. PDEF es tu defensa física: cuanto más alta, menos te duelen los golpes físicos. Otro pasivo que no cuesta nada dejar al máximo."},{"name":"Spear Mastery","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_MaoXiShuLianDu.webp","tag":"Al máximo","desc":"+40 de PATK, con otros +10 adicionales si vas montado."},{"name":"Holy Cross","img":"https://www.roochub.com/icons/UI_Icon_Skill_Crusader_ShengShiZiGongJi.webp","tag":"Solo hasta nivel 5","desc":"No necesitas más: con nivel 5 te alcanza para desbloquear Grand Cross, así que no gastes puntos de más aquí."},{"name":"Grand Cross","img":"https://www.roochub.com/icons/UI_Icon_Skill_Crusader_ShengShiZiShenPan.webp","tag":"Al máximo","desc":"Tu AoE principal, es decir, tu golpe en área, el que alcanza a varios enemigos a la vez: daño mágico de elemento Holy calculado como (PATK + MATK) / 2 × 1200%, repartido entre hasta 10 objetivos. MATK es tu ataque mágico, el equivalente de PATK para el daño de hechizos."},{"name":"Riding","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_QiChengShu.webp","tag":"1 punto","desc":"No te lo saltes solo porque parezca poca cosa: es un único punto y te da acceso a montura."},{"name":"Heal","img":"https://www.roochub.com/icons/UI_Icon_Skill_Acolyte_ZhiYuShu.webp","tag":"Si sobran puntos","desc":"El primer sitio donde repartir los puntos que te queden después de todo lo anterior: te da algo de auto-sostenimiento, o sea, capacidad de curarte tú mismo sin depender de un compañero."},{"name":"Providence","img":"https://www.roochub.com/icons/UI_Icon_Skill_Crusader_ShenYouZhiGuang.webp","tag":"Si aún sobran","desc":"Opción de reserva, solo si todavía tienes margen después de Heal."},{"name":"Auto Guard","img":"https://www.roochub.com/icons/UI_Icon_Skill_Crusader_ZiDongFangYu.webp","tag":"Si aún sobran","desc":"La otra opción de reserva, al mismo nivel de prioridad que Providence."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'paladin-build-pvp-gvg')
  and order_index = 3;

update public.guide_steps
set content = $IMPERIUM$Esta es la joya de la corona: tu tercera clase (Trans. 2nd), donde todo lo anterior se convierte en el build de Paladin que domina el Tyr Cup. Sigue el orden con disciplina — varias de estas habilidades dependen unas de otras para rendir al máximo.

__SKILLS__[{"name":"Fortitude","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_JianYi.webp","tag":"Obligatorio · al máximo","desc":"+15% de Max HP permanente y +12% de reducción de daño físico y mágico. Es el pilar de tu resistencia en esta fase del build."},{"name":"Spear Quicken","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_ChangMaoJiaSuShu.webp","tag":"Al máximo","desc":"Durante 120 segundos te da +45% de ASPD, +20 de CRIT y +20 de FLEE, y además desbloquea el acceso a Sacrifice y Concentrate Pierce. ASPD es tu velocidad de ataque (cuántos golpes das por segundo), CRIT tu probabilidad de golpe crítico y FLEE tu evasión (lo fácil que es que el rival falle contra ti). Actívalo SIEMPRE antes de entrar en la pelea, nunca a mitad de combate: para entonces ya perdiste la ventana en la que más rinde."},{"name":"Sacrifice","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_SheMingGongJi.webp","tag":"Al máximo","desc":"La habilidad con la que cierras la pelea. Convierte tus siguientes 5 ataques normales en golpes forzados que en PvP se calculan sobre un 7% de tu Max HP cada uno, a cambio de consumir alrededor de un 3.5% de tu propia Max HP por golpe, y ralentiza un 20% la velocidad de movimiento del rival golpeado durante 2 segundos. PvP es el combate contra otros jugadores."},{"name":"Devotion","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_XiSheng.webp","tag":"Al máximo","desc":"Redirige hacia ti el 130% del daño que iba a recibir un aliado, durante hasta 120 segundos (se corta si te alejas más de 11 metros de él). Actívalo sobre tu compañero más valioso ANTES de que empiecen a atacarlo, nunca después de que ya esté en apuros."},{"name":"Shield Reflect","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_FanSheDun.webp","tag":"Al máximo","desc":"Refleja un 40% del daño cuerpo a cuerpo que recibes, reduce un 15% el daño cuerpo a cuerpo que te hacen, y suma +15% de reducción de daño físico y mágico, más otro +1% extra por cada 10 puntos de VIT que tengas, hasta +10% adicional. VIT es la vitalidad: sube tu vida y tu aguante, y es la estadística que repartes primero en este build."},{"name":"Concentrate Pierce","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_NingShenCiJi.webp","tag":"Al máximo","desc":"El golpe con el que abres la pelea, sin restarte ni un punto de tu propia vida como sí hace Sacrifice. Inflige 560% de daño físico, y ese multiplicador sube +1% por cada 500 de tu Max HP, hasta +600% extra."},{"name":"Sympathy","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_LianMin.webp","tag":"Al máximo · barato","desc":"Barato y muy rentable: hace que el aliado que lleva tu Devotion te transfiera el 90% de la amenaza que genera contra monstruos. La amenaza decide a quién atacan los monstruos, así que traspasártela a ti es justo lo que quieres cuando eres tú quien aguanta los golpes."},{"name":"Defending Aura","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_GuangZhiDun.webp","tag":"Unos pocos puntos","desc":"Reduce un 30% el daño a distancia y un 10% el daño mágico que recibes durante 120 segundos, pero a cambio resta un 20% de velocidad de movimiento y de ataque. Actívala solo cuando el equipo rival sea mayoritariamente de clases a distancia o mágicas."},{"name":"Gloria Domini","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_ShenZhiWeiYa.webp","tag":"Situacional","desc":"1400% de daño Holy con 2.4 segundos de retardo, que ralentiza un 40% al objetivo y lo inmoviliza 3 segundos al impactar. Ese retardo significa que el golpe no cae al instante, así que tienes que anticiparte al movimiento del rival. Resérvala para inmovilizar a alguien que intenta huir; no la gastes como daño suelto."},{"name":"Battle Chant","img":"https://www.roochub.com/icons/UI_Icon_Skill_Paladin_ShengYin_Buff.webp","tag":"Si sobran puntos","desc":"Un buff aleatorio para todo el grupo (un buff es una mejora temporal). Solo tiene sentido una vez cubierto todo lo anterior."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'paladin-build-pvp-gvg')
  and order_index = 4;

update public.guide_steps
set content = $IMPERIUM$Aquí tienes el equipo de cartas que completa el build. Una carta se inserta en una pieza de equipo y le suma sus efectos; la etiqueta de cada ficha te dice su rareza y la ranura en la que encaja. Por la convención de dos décadas que arrastra esta franquicia, cada carta suele caer del monstruo o jefe que comparte su nombre — tómalo como una referencia orientativa y no como un dato de drop confirmado por un parche concreto de ROOC.

__SKILLS__[{"name":"Eddga","img":"https://www.roochub.com/icons/UI_MonsterCard_Huwang.webp","tag":"Épica · Mano secundaria","desc":"Suma +10% al coste de SP y trae un efecto especial propio; en set con otra pieza, añade +3% de reducción de daño físico. El SP es la energía que gastas al lanzar habilidades, así que ese +10% es un coste, no un beneficio; y «en set» significa que ese bono extra solo se aplica si combinas varias piezas del mismo conjunto. Lo suelta el jefe o MVP que comparte su nombre."},{"name":"Angeling","img":"https://www.roochub.com/icons/UI_MonsterCard_Tianshiboli.webp","tag":"Épica · Armadura","desc":"+5% de Max HP y cambia el elemento de tu armadura a Holy; en set, suma otro +3% de Max HP. La deja caer el MVP Angeling — MVP es el jefe más fuerte de una zona, y sus cartas están entre las más difíciles de conseguir."},{"name":"Osiris","img":"https://roocdb.com/cards/Esailisi.webp","tag":"MVP · Accesorio","desc":"Funciona como un seguro de vida: si un golpe de habilidad te iba a matar, en su lugar te deja con 1 HP, te vuelve invulnerable durante 3 segundos y te devuelve un 70% de tu HP y SP de golpe (con 3 minutos de reutilización antes de poder repetirlo). Súmale el despertar completo y ganas otro +10% de reducción de daño físico y mágico, más +6% de Max HP. Es, con diferencia, la carta más difícil de conseguir de esta lista: solo la suelta el jefe de campo Osiris."},{"name":"Horn","img":"https://roocdb.com/cards/Qiaoxingchong.webp","tag":"Épica · Mano secundaria","desc":"Reduce un 20% el daño base que recibes, y su despertar puede llevarte hasta +400 de defensa total al llegar al nivel 15. Al caer de un monstruo de campo corriente, es de las piezas más fáciles de conseguir de toda esta lista."},{"name":"Doppelganger","img":"https://www.roochub.com/icons/UI_MonsterCard_Siling.webp","tag":"Épica · Arma","desc":"+10% de ASPD, +5 de AGI, +5 de CRIT y +12% de daño crítico: justo lo que necesitas para acelerar tu combo de Sacrifice. AGI es la agilidad, la estadística que empuja tu velocidad de ataque y tu evasión. La suelta el MVP Doppelganger."},{"name":"Drake","img":"https://www.roochub.com/icons/UI_MonsterCard_Haidaozhiwang.webp","tag":"Épica · Arma","desc":"Suma +12% de daño físico y mágico, y si consigues el set completo, otro +3% de ataque de arma. La deja caer el MVP Drake."},{"name":"Fabre","img":"https://www.roochub.com/icons/UI_MonsterCard_Lvmianchong.webp","tag":"Común · Arma","desc":"Solo +1 de VIT y +100 de Max HP, pero al caer de un monstruo de campo muy temprano y accesible, funciona bien como relleno mientras subes de nivel."},{"name":"Baphomet Jr.","img":"https://www.roochub.com/icons/UI_MonsterCard_Xiaobafengte.webp","tag":"Poco común · Prenda","desc":"+1 de CRIT y +3 de AGI. Es un monstruo de campo de rareza intermedia, mucho más accesible que la carta del Baphomet original, que sí es MVP. No la confundas con la mascota del mismo nombre del siguiente paso: aquí hablamos de la carta."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'paladin-build-pvp-gvg')
  and order_index = 6;

update public.guide_steps
set content = $IMPERIUM$Dos mascotas completan el build, cada una con un rol distinto.

__SKILLS__[{"name":"Baphomet Jr.","img":"https://roocdb.com/pets/Pokemon_bafengte.webp","tag":"DPS de área","desc":"Lleva Harvesting Scythe, una habilidad pasiva que le devuelve vida a ella y a su dueño cada vez que uno de sus golpes es crítico: un 3% de ese daño se convierte en curación, porcentaje que llega al 9% si le subes las 10 mejoras al máximo (2,430 fragmentos en total). Esos fragmentos se compran en la Pet Shop a cambio de Poring Coins, que se ganan cazando monstruos de tipo Mini y MVP."},{"name":"Sohee","img":"https://roocdb.com/pets/Pokemon_guinv.webp","tag":"Soporte","desc":"Es la pareja recomendada para Baphomet Jr. en un build que gira en torno a Sacrifice, precisamente porque su apoyo compensa el desgaste de vida que supone activar esa habilidad una y otra vez. Su habilidad exclusiva, Lucid Dream, da a Sohee y a su dueño +10% de velocidad de ataque, +5% de velocidad de movimiento y 2% de robo de vida durante 8 segundos (a cambio de +3 segundos de reutilización de habilidades), y llega a +30%/+12%/5% en el Tier 10."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'paladin-build-pvp-gvg')
  and order_index = 7;

update public.guide_steps
set content = $IMPERIUM$El árbol de Swordsman es el mismo para todo el que empieza por esta rama — Knight, Crusader, y sus evoluciones — así que si ya conoces el build de Paladin, este primer tramo te sonará. Aun así importa: aquí sientas la base de ataque físico antes de pasar a Knight y, después, a Lord Knight. Cada ficha lleva el icono de la habilidad tal y como la verás en el juego, la prioridad que le damos y para qué sirve.

__SKILLS__[{"name":"Sword Mastery","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_JianXiShuLianDu.webp","tag":"Al máximo","desc":"+30 de PATK permanente mientras llevas espada equipada. PATK es tu ataque físico: cuanto más alto, más daño hacen tus golpes normales y tus habilidades físicas. Es pasivo y no cuesta nada mantenerlo al día."},{"name":"Bash","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_kuangJi.webp","tag":"Al máximo","desc":"Tu primer golpe de verdad: 350% + 200 de daño físico (PDMG) a un único objetivo, y suma +15 de HIT. HIT es tu puntería: cuanto más tengas, menos fallas contra rivales esquivos."},{"name":"Fatal Blow","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_GongJiRuoDian.webp","tag":"Al máximo","desc":"+25% de probabilidad de aturdir cada vez que conectas ese mismo Bash. Un rival aturdido se queda unos instantes sin poder moverse ni atacar."},{"name":"Increase Recuperative Power","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_KuaiSuHuiFu.webp","tag":"Al máximo","desc":"Tu regeneración de HP pasiva —la vida que recuperas tú solo con el paso del tiempo— pasa a restaurar 50 puntos fijos + 1% de tu HP máx. cada 10 segundos. Nada vistoso, pero lo necesitas antes de que tu HP empiece a escalar en las siguientes fases del build."},{"name":"Magnum Break","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_NuBao.webp","tag":"Unos pocos puntos","desc":"250% + 100 de daño físico de elemento Fuego a hasta 10 objetivos a tu alrededor, con empuje incluido: es un golpe en área, no contra un solo enemigo. No es prioridad, pero unos pocos puntos rinden mucho en peleas de gremio donde el rival se amontona."},{"name":"Berserk","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_KuangBaoZhuangTai.webp","tag":"1 punto","desc":"Esta es la versión barata de primer trabajo: solo +10 de PATK permanente, pero por un único punto no hay motivo para saltárselo. No la confundas con el Berserk de Lord Knight del paso 4: son habilidades distintas, con iconos distintos, y aquella es muchísimo más potente."},{"name":"Provoke","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_TiaoXing.webp","tag":"Si sobran puntos","desc":"Queda para el final: rinde casi solo contra monstruos y en combate contra jugadores apenas se nota."},{"name":"Endure","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_BaTi.webp","tag":"Si sobran puntos","desc":"Mismo caso que Provoke: rinde casi solo contra monstruos y en combate contra jugadores apenas se nota."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'lord-knight-build')
  and order_index = 2;

update public.guide_steps
set content = $IMPERIUM$Knight es tu segundo trabajo, y aquí el camino se separa del Crusader/Paladin: no hay escudo, no hay Grand Cross, no hay soporte. Todo lo que ganas aquí es capacidad de aguante y de golpe. Sigue este orden.

__SKILLS__[{"name":"Spear Mastery","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_MaoXiShuLianDu.webp","tag":"Al máximo","desc":"+40 de PATK permanente, +10 adicionales si vas montado. PATK es tu ataque físico, y esta pasiva es la base de daño de todo este segundo tramo."},{"name":"Sturdy Strike","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_JianDingDaJi.webp","tag":"Al máximo","desc":"Tu golpe principal en esta fase: (1 + VIT/300) × 500% + 500 de daño físico Neutral a un único objetivo, y además te otorga un +10% de reducción de daño físico cada vez que lo usas. VIT es la vitalidad, la estadística que sube tu vida y tu aguante; «Neutral» quiere decir que el golpe no lleva elemento (ni fuego, ni agua…), así que no le afectan las resistencias elementales del rival. Cuanto más VIT lleves, más pega y más aguantas — la razón por la que esta clase prioriza VIT desde el primer punto."},{"name":"Lion Roar","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_ShiZiFenXun.webp","tag":"Al máximo · requiere Sturdy Strike Nv.5","desc":"Tu AoE de esta fase, es decir, tu golpe en área: 750% + 600 de daño físico Neutral a hasta 10 objetivos cercanos, con un 20% de ralentización durante 3 segundos. También lleva una pasiva: 10% de probabilidad de activar un efecto adicional (Lion Howling) cada vez que te golpean, con 4 segundos de reutilización interna."},{"name":"Iron Will","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_GangTieYiZhi.webp","tag":"Al máximo · requiere Lion Roar Nv.5","desc":"Tu red de seguridad: cuando tu HP cae por debajo del 30%, se activa automáticamente un escudo que absorbe daño equivalente al 20% de tu HP máx. durante 10 segundos, con 45 segundos de reutilización a nivel máximo."},{"name":"Riding","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_QiChengShu.webp","tag":"1 punto · si sobran","desc":"Un único punto te da acceso a montura. Junto con Cavalier Mastery es lo primero en lo que repartir los puntos que te sobren, por la movilidad que ganas en GvG."},{"name":"Cavalier Mastery","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_QiBingXiuLian.webp","tag":"Si sobran puntos","desc":"Hasta el máximo: entre +8% y +40% de velocidad de movimiento montado, según el nivel al que la subas."},{"name":"Brandish Spear","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_QiChengGongJi.webp","tag":"Si aún sobran","desc":"Una de las dos opciones para sumar más daño en área, una vez cubiertos el núcleo y la movilidad."},{"name":"Spear Stab","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_ChangMaoCiJi.webp","tag":"Si aún sobran","desc":"La otra opción para sumar más daño en área, al mismo nivel de prioridad que Brandish Spear."},{"name":"Sword Quicken","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_JianGongSuZengJia.webp","tag":"Camino alternativo","desc":"ASPD +35% durante 240 segundos. ASPD es tu velocidad de ataque: cuántos golpes das por segundo. Es además la puerta de entrada a Bowling Bash."},{"name":"Bowling Bash","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_GuaiWuHuJi.webp","tag":"Camino alternativo","desc":"El destino al que lleva Sword Quicken: una alternativa válida si prefieres un perfil más rápido y menos tanque. Ojo, con el reparto de puntos de esta guía no llegas a los dos caminos a la vez — o el núcleo de aguante, o este — así que elige uno."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'lord-knight-build')
  and order_index = 3;

update public.guide_steps
set content = $IMPERIUM$Esta es tu clase final (Trans. 2nd), donde todo lo anterior converge en el Lord Knight que domina la línea de frente. Sigue el orden con disciplina — aquí no hay escudo ni aliado que te cubra: cada habilidad de este árbol existe para que resuelvas la pelea tú solo.

__SKILLS__[{"name":"Aura Blade","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_LingQiJian.webp","tag":"Al máximo","desc":"Tu buff permanente de combate (un buff es una mejora temporal que te activas tú): durante 120 segundos, cada ataque tuyo suma 700 + (10 × tu Nivel Base) de daño físico que ignora la defensa del rival, aumenta tu daño físico un 10% adicional, y ralentiza un 20% la velocidad de movimiento del objetivo golpeado durante 3 segundos. Actívalo SIEMPRE antes de entrar en la pelea — no sirve de nada a mitad de intercambio."},{"name":"Concentration","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_JiZhongGongJi.webp","tag":"Al máximo","desc":"Tu otro buff de apertura: +50 de HIT y +45% de ATK de arma durante 120 segundos, a cambio de un -25% en tu propia PDEF. PDEF es tu defensa física, lo que amortigua los golpes físicos que recibes. Actívalo junto a Aura Blade antes de la pelea, pero ten en cuenta esa bajada de defensa si el equipo rival lleva mucho daño físico encima — no es gratis."},{"name":"Clashing Spiral","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_LuoXuanJiCi.webp","tag":"Al máximo","desc":"Tu ejecutor de objetivo único: hasta 2000% de daño físico Neutral (el multiplicador en PvP baja a 500%; PvP es el combate contra otros jugadores) e inmoviliza al rival durante 1 segundo al impactar. Resérvalo para rematar a alguien ya dañado o para trabar a quien intenta huir, no lo gastes como un golpe suelto más."},{"name":"Berserk","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_KuangNuZhiQiang.webp","tag":"Al máximo con 5 puntos","desc":"La versión de Trans. 2nd, la de verdad: tu botón de todo o nada. Te cura por completo, sube tu HP máx. al 150%, y te da +100% de PATK base y de arma, más +25% de velocidad de movimiento. El precio es que pierdes un 3% de tu HP máx. cada segundo mientras dura, y se corta sola si bajas del 10% de HP o pasan 15 segundos. Si llevas espada, además ganas +30% de ASPD y +25% de daño crítico durante 15 segundos; si llevas lanza, en su lugar ganas -100% de tiempo de lanzamiento fijo y -50% de reutilización global durante 8 segundos. Actívalo para cerrar una pelea ya decidida, nunca para abrir una que todavía puedes perder."},{"name":"Tension Relax","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_JiSuHuiFu.webp","tag":"Hasta 5 puntos","desc":"Tu recuperación de emergencia: restaura un 30% de tu HP máx. al instante y otro 12% por segundo durante los siguientes 5 segundos, casi un 90% de tu vida total si lo dejas completarse. Es lo que te permite sobrevivir al desgaste que deja Berserk detrás."},{"name":"Rune of Faith","img":"https://www.roochub.com/icons/UI_icon_item_fuwenshi03.webp","tag":"1 punto","desc":"Barato y siempre rentable: elimina algunos efectos de estado activos y te da inmunidad a nuevos efectos de estado durante 2 segundos. Los efectos de estado son cosas como aturdimientos o inmovilizaciones, así que es un único punto por una salida de emergencia."},{"name":"Parry","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_ShuangJianGeDang.webp","tag":"Si sobran puntos","desc":"35% de probabilidad de parry de daño físico durante 60 segundos activado, con una versión pasiva más débil del 10% siempre presente. Hacer parry es desviar el golpe para que no te haga daño."},{"name":"Head Crush","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_ShangHaiZengYa.webp","tag":"Si sobran puntos","desc":"Primer paso de la otra vía para los puntos sobrantes: la pareja Head Crush → Joint Beat encadena sangrado y un proc pasivo cada vez que usas otra habilidad."},{"name":"Joint Beat","img":"https://www.roochub.com/icons/UI_Icon_Skill_Swordman_QiaoDa.webp","tag":"Si sobran puntos","desc":"El segundo paso de esa vía, el que completa la pareja con Head Crush: entre las dos encadenan sangrado y un proc pasivo cada vez que usas otra habilidad (un proc es un efecto que se dispara solo, sin que tú lo actives)."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'lord-knight-build')
  and order_index = 4;

update public.guide_steps
set content = $IMPERIUM$Aquí tienes el equipo de cartas que completa el build, elegido por cómo encaja con el kit de Lord Knight: golpes porcentuales constantes, VIT como stat clave, y ninguna red de seguridad externa (a diferencia del Paladin, aquí no hay Devotion que te cubra). Una carta se inserta en una pieza de equipo y le suma sus efectos; la etiqueta de cada ficha te dice su rareza y la ranura en la que encaja. Por la convención de dos décadas que arrastra esta franquicia, cada carta suele caer del monstruo o jefe que comparte su nombre — tómalo como referencia orientativa, no como un dato de drop confirmado por un parche concreto de ROOC.

__SKILLS__[{"name":"Gryphon","img":"https://www.roochub.com/icons/UI_MonsterCard_shijiushou.webp","tag":"Rara · Arma","desc":"FLEE +2, CRIT +7, y un 8% de probabilidad en cada ataque físico de lanzar automáticamente un Bowling Bash Nv.5 (CD: 0,5s; la probabilidad se acumula con varias copias). FLEE es tu evasión, CRIT tu probabilidad de golpe crítico y «CD» es el tiempo de reutilización, lo que tarda algo en poder volver a activarse. Es la carta más temática de esta lista: Bowling Bash es una de tus propias habilidades del árbol Knight, así que esta carta literalmente te la dispara gratis de vez en cuando."},{"name":"Doppelganger","img":"https://www.roochub.com/icons/UI_MonsterCard_Siling.webp","tag":"Épica · Arma","desc":"ASPD +10%, AGI +5, CRIT +5 y +12% de daño crítico; en set, +2% de ASPD adicional. AGI es la agilidad, y «en set» significa que ese bono extra solo se aplica si combinas varias piezas del mismo conjunto. Acelera tanto tus ataques básicos, ya reforzados por Aura Blade, como tu ventana de Concentration."},{"name":"Drake","img":"https://www.roochub.com/icons/UI_MonsterCard_Haidaozhiwang.webp","tag":"Épica · Arma","desc":"+12% de daño físico y mágico; en set, +3% de ATK de arma. Daño plano sin condiciones, siempre rinde."},{"name":"Orc Hero","img":"https://www.roochub.com/icons/UI_MonsterCard_Shourenyingxiong.webp","tag":"Épica · Cabeza superior","desc":"VIT +8 y, cada 6 segundos, elimina el Aturdimiento activo y te da inmunidad a Aturdimiento durante 4 segundos; en set, +3% de daño físico. La inmunidad a aturdimiento es oro puro para una clase que necesita mantenerse pegada al rival para que Clashing Spiral y Berserk rindan."},{"name":"Orc Lord","img":"https://www.roochub.com/icons/UI_MonsterCard_Shourenqiuzhang.webp","tag":"Épica · Armadura","desc":"Al recibir ataques físicos, refleja un 20% de ese daño a quien te golpeó, +0,2% adicional por cada punto de VIT que lleves (máximo 40%), con 4 segundos de reutilización; en set, +3% de reducción de daño físico. Con VIT como tu stat principal, este reflejo escala solo con el resto de tu build."},{"name":"Horn","img":"https://www.roochub.com/icons/UI_MonsterCard_Qiaoxingchong.webp","tag":"Rara · Mano secundaria","desc":"Reduce un 20% el daño físico que recibes; en set, +1% de resistencia a criaturas pequeñas. Cae de un monstruo de campo corriente, así que es de las piezas más accesibles de toda la lista."},{"name":"Steel Fur Grizzly","img":"https://www.roochub.com/icons/UI_MonsterCard_gangzongjuxiong.webp","tag":"Rara · Cabeza superior","desc":"VIT +5, y cuando tu HP baja del 30%, el daño que recibes fuera de efectos de estado se reduce otro 10% adicional, sin tiempo de reutilización; en set, +1% de HP máx. Encaja directamente con Berserk, que te deja igual de bajo de HP como parte de su propio coste."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'lord-knight-build')
  and order_index = 6;

update public.guide_steps
set content = $IMPERIUM$De las 9 mascotas ya montadas en la sección de Mascotas, estas son las dos que mejor encajan con Lord Knight.

__SKILLS__[{"name":"Dr. Owl","img":"https://roocdb.com/pets/Pokemon_maotouyingboshi.webp","tag":"DPS de objetivo único · Bruto","desc":"La recomendada. Su habilidad exclusiva, Gale Wind, dispara una flecha de viento que inflige 800% de daño físico a tu objetivo y además aumenta un 20% el daño físico que ese objetivo recibe — porcentaje que sube a 1200% de daño y +30% de daño físico recibido en el Tier 10 (2.430 Pet Shard en total repartidos entre las 10 mejoras, comprados con Poring Coins en la Pet Shop). Ese debuff (un debuff es un efecto negativo que le cuelgas al rival) de +20/30% de daño físico recibido se suma directamente sobre tu propio Clashing Spiral y tus ataques básicos reforzados por Aura Blade: es un multiplicador de daño físico sobre el mismo objetivo que ya estás golpeando, no una habilidad que compite con la tuya."},{"name":"Sohee","img":"https://roocdb.com/pets/Pokemon_guinv.webp","tag":"Soporte · Semihumano","desc":"La alternativa razonable si prefieres priorizar el aguante sobre el remate: su Lucid Dream da +10% de ASPD, +5% de velocidad de movimiento y 2% de robo de vida durante 8 segundos (a cambio de +3 segundos de reutilización de habilidades), subiendo a +30%/+12%/5% en el Tier 10 — el mismo tipo de sustento que recomendamos para Paladin, útil aquí para compensar el desgaste de HP que deja Berserk."}]$IMPERIUM$,
    images  = array[]::text[]
where guide_id = (select g.id from public.guides g join public.games gm on gm.id = g.game_id
                  where gm.slug = 'ragnarok-origin-classic' and g.slug = 'lord-knight-build')
  and order_index = 7;
